// ─── GERA\u00c7\u00c3O ──────────────────────────────────────────────────────────────
function generateAppJS(schedules) {
  const lines = JSON.stringify(schedules, null, 2)
    .replace(/"times"/g, 'times')
    .replace(/"weekday"/g, 'weekday')
    .replace(/"saturday"/g, 'saturday')
    .replace(/"sunday"/g, 'sunday')
    .replace(/"holiday"/g, 'holiday')
    .replace(/"from"/g, 'from')
    .replace(/"to"/g, 'to')
    .replace(/"name"/g, 'name')
    .replace(/"code"/g, 'code')
    .replace(/"city"/g, 'city')
    .replace(/"operator"/g, 'operator')
    .replace(/"source"/g, 'source')
    .replace(/"info"/g, 'info');

  return `// ═══════════════════════════════════════════════════════════════
// GERADO POR scripts/atualizar-horarios.mjs
// Fontes confi\u00e1veis:
//   termialcastelo.com  \u2192  DETRO/RJ (linhas Cidade do A\u00e7o)
//   onibus.online       \u2192  Quadros municipais
// ═══════════════════════════════════════════════════════════════
var SCHEDULES = ${lines};
`;
}

// ─── MAIN ──────────────────────────────────────────────────────────────────
const args = process.argv.slice(2);
const isDryRun = args.includes('--dry-run');
const writeApp = args.includes('--write-app');

const outDir = join(ROOT, 'scripts');
if (!existsSync(outDir)) mkdirSync(outDir, { recursive: true });
writeFileSync(join(outDir, 'dados-linhas.json'), JSON.stringify(SCHEDULES, null, 2));

if (isDryRun) {
  console.log('🔍 DRY RUN \u2014 Nenhum arquivo foi alterado.');
  console.log(`   ${SCHEDULES.length} linhas carregadas`);
  console.log('   dados salvos em: scripts/dados-linhas.json');
  console.log('\n   Fontes:');
  for (const [key, val] of Object.entries(SOURCE_NOTES)) {
    console.log(`   ${key}: ${val.url}`);
  }
  process.exit(0);
}

if (writeApp) {
  const appContent = generateAppJS(SCHEDULES);
  writeFileSync(join(ROOT, 'app.js'), appContent);
  console.log(`\u2705 app.js atualizado com ${SCHEDULES.length} linhas`);
}

console.log(`\uD83D\uDCCA ${SCHEDULES.length} linhas salvas em scripts/dados-linhas.json`);
console.log('\n\uD83D\uDCE1 Fontes:');
for (const [key, val] of Object.entries(SOURCE_NOTES)) {
  console.log(`   ${key}`);
  console.log(`      ${val.url}`);
  console.log(`      ${val.desc}`);
}
console.log('\n\u25B6\uFE0F  Para gerar o app.js:  node scripts/atualizar-horarios.mjs --write-app');
console.log('\u25B6\uFE0F  Para teste (dry-run): node scripts/atualizar-horarios.mjs --dry-run');
